5		export interface GraphIssue {
6			kind: string;
7			path: string | null;
8			id: string | null;
9			message: string;
10			relatedPath: string | null;
11		}
12	
13		let { issues }: { issues: GraphIssue[] } = $props();
14	
15		const KIND_LABELS: Record<string, string> = {
16			duplicate_id: 'Duplicate ID',
17			missing_dep: 'Missing dep target',
18			id_path_missing: 'Broken id_to_path',
19			id_path_mismatch: 'id_to_path mismatch',
20			parse_error: 'Parse error',
21			required_root_missing: 'Required root missing',
22			cascade_unknown: 'Unknown cascade target',
23			cycle: 'Cycle'
24		};
25	
26		function labelFor(kind: string): string {
27			return KIND_LABELS[kind] ?? kind;
28		}
29	
30		const groups = $derived.by(() => {
31			const map = new Map<string, GraphIssue[]>();
32			for (const issue of issues) {
33				const list = map.get(issue.kind) ?? [];
34				list.push(issue);
35				map.set(issue.kind, list);
36			}
37			return Array.from(map.entries())
38				.map(([kind, list]) => ({ kind, issues: list }))
39				.sort((a, b) => labelFor(a.kind).localeCompare(labelFor(b.kind)));
40		});
41	
42		let expanded = $state<Record<string, boolean>>({});
43	
44		function toggle(kind: string) {
45			expanded[kind] = !expanded[kind];
46		}
47	
48		function docLink(path: string | null): string | null {
49			if (!path) return null;
50			const p = $page.params as Record<string, string>;
51			const nodeId = p['nodeId'];
52			const projectId = p['projectId'];
53			if (!nodeId || !projectId) return null;
54			const segments = path
55				.split('/')
56				.filter((s) => s.length > 0)
57				.map(encodeURIComponent)
58				.join('/');
59			return `/nodes/${nodeId}/projects/${projectId}/documents/${segments}`;
60		}
61	
62		// Deterministic mirror of cli/internal/docgraph.SuggestUniqueID; we keep a
63		// browser-side copy so the "copy unique id" button works without a
64		// round-trip. Keep in sync with the Go implementation's SHA-1 truncation.
65		async function suggestUniqueID(id: string | null, path: string | null): Promise<string> {
66			const safePath = (path ?? '').trim();
67			const safeID = (id ?? '').trim();
68			const encoder = new TextEncoder();
69			const digest = await crypto.subtle.digest('SHA-1', encoder.encode(safePath));
70			const bytes = new Uint8Array(digest);
71			const suffix = Array.from(bytes.slice(0, 4))
72				.map((b) => b.toString(16).padStart(2, '0'))
73				.join('');
74			if (safeID === '') return `doc-${suffix}`;
75			return `${safeID}-${suffix}`;
76		}
77	
78		async function copySuggestion(issue: GraphIssue, event: Event) {
79			event.stopPropagation();
80			const suggestion = await suggestUniqueID(issue.id, issue.path);
81			try {
82				await navigator.clipboard.writeText(suggestion);
83			} catch {
84				// Clipboard API unavailable (e.g. non-secure context) — surface the
85				// suggestion inline so the user can still copy it manually.
86				window.prompt('Copy suggested unique id:', suggestion);
87			}
88		}
89	
90		async function copyMessage(issue: GraphIssue, event: Event) {
91			event.stopPropagation();
92			try {
93				await navigator.clipboard.writeText(issue.message);
94			} catch {
95				window.prompt('Copy issue message:', issue.message);
96			}
97		}
98	
99		function dependencyRemovalSnippet(issue: GraphIssue): string {
100			const id = (issue.id ?? '').trim();
101			if (!id) return '';
102			return `    - ${id}`;
103		}
104	
105		async function copyDependencyRemovalSnippet(issue: GraphIssue, event: Event) {
106			event.stopPropagation();
107			const snippet = dependencyRemovalSnippet(issue);
108			if (!snippet) return;
109			try {
110				await navigator.clipboard.writeText(snippet);
111			} catch {
112				window.prompt('Copy frontmatter line to remove:', snippet);
113			}
114		}
